DROP TABLE IF EXISTS `xing_bill`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `xing_bill` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT '编号',
  `title` varchar(200) DEFAULT NULL COMMENT '标题',
  `amount` double NOT NULL DEFAULT '0' COMMENT '金额',
  `type` varchar(11) DEFAULT 'income' COMMENT '类型，默认收入',
  `tags` text COMMENT '标签',
  `detail` text COMMENT '详情',
  `data_time` varchar(100) DEFAULT NULL COMMENT '时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_delete` int(11) DEFAULT '0' COMMENT '被删除',
  `user_id` int(11) DEFAULT '1' COMMENT '用户',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=196 DEFAULT CHARSET=utf8;
